object AppLogger {
    private const val MAX_LOG_CHUNK_SIZE = 4000

    fun init(debug: Boolean = true) {
        Timber.uprootAll()
        if (debug) {
            Timber.plant(VerboseDebugTree())
        } else {
            Timber.plant(VerboseReleaseTree())
        }
    }

    fun v(tag: String, message: String, throwable: Throwable? = null) = log(Log.VERBOSE, tag, message, throwable)
    fun d(tag: String, message: String, throwable: Throwable? = null) = log(Log.DEBUG, tag, message, throwable)
    fun i(tag: String, message: String, throwable: Throwable? = null) = log(Log.INFO, tag, message, throwable)
    fun w(tag: String, message: String, throwable: Throwable? = null) = log(Log.WARN, tag, message, throwable)
    fun e(tag: String, message: String, throwable: Throwable? = null) = log(Log.ERROR, tag, message, throwable)

    fun logException(tag: String, throwable: Throwable, context: String? = null) {
        val prefix = context?.let { "$it\n" } ?: ""
        e(tag, prefix + Log.getStackTraceString(throwable), throwable)
    }

    fun logAuthAttempt(
        username: String?,
        method: String,
        success: Boolean,
        failureReason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val message = buildString {
            append("AUTH_ATTEMPT")
            append(" method=").append(method)
            append(" username=").append(username ?: "null")
            append(" success=").append(success)
            if (!success) append(" failureReason=").append(failureReason ?: "unknown")
            if (metadata.isNotEmpty()) append(" metadata=").append(metadata)
        }
        if (success) i("AuthLogger", message) else w("AuthLogger", message)
    }

    fun logDatabaseQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rowsAffected: Int? = null,
        source: String? = null
    ) {
        val message = buildString {
            append("DB_QUERY")
            if (source != null) append(" source=").append(source)
            append(" sql=").append(sql)
            append(" parameters=").append(parameters)
            if (durationMs != null) append(" durationMs=").append(durationMs)
            if (rowsAffected != null) append(" rowsAffected=").append(rowsAffected)
        }
        v("DatabaseLogger", message)
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Headers,
        requestBody: String?,
        responseCode: Int? = null,
        responseHeaders: Headers? = null,
        responseBody: String? = null,
        durationMs: Long? = null
    ) {
        val message = buildString {
            append("API_CALL")
            append("\nmethod=").append(method)
            append("\nurl=").append(url)
            append("\nrequestHeaders=").append(headers.toMultimap())
            append("\nrequestBody=").append(requestBody ?: "null")
            if (responseCode != null) append("\nresponseCode=").append(responseCode)
            if (responseHeaders != null) append("\nresponseHeaders=").append(responseHeaders.toMultimap())
            if (responseBody != null) append("\nresponseBody=").append(responseBody)
            if (durationMs != null) append("\ndurationMs=").append(durationMs)
        }
        v("ApiLogger", message)
    }

    private fun log(priority: Int, tag: String, message: String, throwable: Throwable?) {
        val fullMessage = if (throwable != null) {
            if (message.isBlank()) Log.getStackTraceString(throwable)
            else "$message\n${Log.getStackTraceString(throwable)}"
        } else {
            message
        }

        if (fullMessage.length <= MAX_LOG_CHUNK_SIZE) {
            Timber.tag(tag).log(priority, fullMessage)
            return
        }

        var start = 0
        val length = fullMessage.length
        while (start < length) {
            val end = (start + MAX_LOG_CHUNK_SIZE).coerceAtMost(length)
            Timber.tag(tag).log(priority, fullMessage.substring(start, end))
            start = end
        }
    }

    private class VerboseDebugTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            super.log(priority, tag ?: "AppLogger", message, t)
        }
    }

    private class VerboseReleaseTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            when (priority) {
                Log.VERBOSE, Log.DEBUG, Log.INFO, Log.WARN, Log.ERROR, Log.ASSERT -> {
                    Log.println(priority, tag ?: "AppLogger", message)
                    if (t != null) {
                        Log.println(Log.ERROR, tag ?: "AppLogger", Log.getStackTraceString(t))
                    }
                }
            }
        }
    }
}

class VerboseNetworkLoggingInterceptor(
    private val logHeaders: Boolean = true,
    private val logBodies: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startNs = System.nanoTime()

        val requestBodyString = if (logBodies) request.body?.safeReadAsString() else null
        val requestHeaders = if (logHeaders) request.headers else Headers.headersOf()

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = requestHeaders,
            requestBody = requestBodyString
        )

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

            val peekedBody = if (logBodies) response.peekBody(Long.MAX_VALUE).string() else null
            val responseHeaders = if (logHeaders) response.headers else Headers.headersOf()

            AppLogger.logApiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = requestHeaders,
                requestBody = requestBodyString,
                responseCode = response.code,
                responseHeaders = responseHeaders,
                responseBody = peekedBody,
                durationMs = tookMs
            )

            response
        } catch (e: Exception) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            AppLogger.logException(
                tag = "ApiLogger",
                throwable = e,
                context = buildString {
                    append("API_FAILURE")
                    append(" method=").append(request.method)
                    append(" url=").append(request.url)
                    append(" headers=").append(requestHeaders.toMultimap())
                    append(" requestBody=").append(requestBodyString)
                    append(" durationMs=").append(tookMs)
                }
            )
            throw e
        }
    }

    private fun RequestBody.safeReadAsString(): String {
        return try {
            val buffer = Buffer()
            writeTo(buffer)
            val charset: Charset = contentType().charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        } catch (e: Exception) {
            "!! unable to read request body: ${e.message}"
        }
    }

    private fun MediaType?.charset(default: Charset): Charset {
        return try {
            this?.charset(default) ?: default
        } catch (_: Exception) {
            default
        }
    }
}

object LoggingOkHttpFactory {
    fun create(baseBuilder: OkHttpClient.Builder = OkHttpClient.Builder()): OkHttpClient {
        return baseBuilder
            .addInterceptor(VerboseNetworkLoggingInterceptor())
            .build()
    }
}

object DatabaseLogger {
    fun logQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rowsAffected: Int? = null,
        source: String? = null
    ) {
        AppLogger.logDatabaseQuery(
            sql = sql,
            parameters = parameters,
            durationMs = durationMs,
            rowsAffected = rowsAffected,
            source = source
        )
    }

    inline fun <T> traceQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        source: String? = null,
        block: () -> T
    ): T {
        val start = System.nanoTime()
        return try {
            val result = block()
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            val rowsAffected = when (result) {
                is Collection<*> -> result.size
                is Array<*> -> result.size
                is Int -> result
                else -> null
            }
            logQuery(sql, parameters, durationMs, rowsAffected, source)
            result
        } catch (e: Exception) {
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.logException(
                "DatabaseLogger",
                e,
                "DB_QUERY_FAILURE source=$source sql=$sql parameters=$parameters durationMs=$durationMs"
            )
            throw e
        }
    }
}

object AuthLogger {
    fun logSuccess(
        username: String?,
        method: String,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.logAuthAttempt(
            username = username,
            method = method,
            success = true,
            metadata = metadata
        )
    }

    fun logFailure(
        username: String?,
        method: String,
        failureReason: String?,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.logAuthAttempt(
            username = username,
            method = method,
            success = false,
            failureReason = failureReason,
            metadata = metadata
        )
    }

    inline fun <T> traceAuthentication(
        username: String?,
        method: String,
        metadata: Map<String, Any?> = emptyMap(),
        block: () -> T
    ): T {
        return try {
            val result = block()
            logSuccess(username, method, metadata)
            result
        } catch (e: Exception) {
            logFailure(username, method, e.message, metadata)
            AppLogger.logException("AuthLogger", e, "AUTH_EXCEPTION username=$username method=$method metadata=$metadata")
            throw e
        }
    }
}

object ExceptionLogger {
    fun log(throwable: Throwable, context: String? = null, tag: String = "ExceptionLogger") {
        AppLogger.logException(tag, throwable, context)
    }

    inline fun <T> trace(tag: String = "ExceptionLogger", context: String? = null, block: () -> T): T {
        return try {
            block()
        } catch (e: Exception) {
            AppLogger.logException(tag, e, context)
            throw e
        }
    }
}

class GlobalExceptionHandler(
    private val defaultHandler: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.logException(
            tag = "GlobalCrashLogger",
            throwable = throwable,
            context = "UNCAUGHT_EXCEPTION thread=${thread.name} id=${thread.id}"
        )
        defaultHandler?.uncaughtException(thread, throwable)
    }
}

object LoggingInitializer {
    fun initialize(debug: Boolean = true) {
        AppLogger.init(debug)
        Thread.setDefaultUncaughtExceptionHandler(GlobalExceptionHandler())
    }
}